SELECT COUNT(1) FROM HYMNS HM
HM.VISIBLE_FLG = 'true'
AND HM.NAME_JP = #{nameJp}

SELECT COUNT(1)
FROM HYMNS HM

    HM.VISIBLE_FLG = 'true'

        AND HM.NAME_JP = #{nameJp}


        AND HM.ID <> #{id}

SELECT COUNT(1) FROM HYMNS HM
HM.VISIBLE_FLG = 'true'
AND HM.NAME_KR = #{nameKr}

SELECT COUNT(1)
FROM HYMNS HM

    HM.VISIBLE_FLG = 'true'

        AND HM.NAME_KR = #{nameKr}


        AND HM.ID <> #{id}

SELECT HM.ID, HM.NAME_JP, HM.NAME_KR, HM.LINK, HM.UPDATED_TIME, HM.UPDATED_USER, HM.LYRIC, HM.VISIBLE_FLG, HM.CLASSICAL FROM HYMNS HM
HM.ID = #{id}
AND HM.VISIBLE_FLG = 'true'

mapper.insert:
INSERT INTO HYMNS (
    ID, NAME_JP, NAME_KR, LINK,
    UPDATED_TIME, UPDATED_USER,
    LYRIC, VISIBLE_FLG, CLASSICAL
) VALUES (
    #{id}, #{nameJp}, #{nameKr}, #{link},
    #{updatedTime}, #{updatedUser},
    #{lyric}, #{visibleFlg}, #{classical}
)

mapper.update:
UPDATE HYMNS
NAME_JP = #{nameJp}, NAME_KR = #{nameKr}, LINK = #{link}, UPDATED_TIME = #{updatedTime}, UPDATED_USER = #{updatedUser}, LYRIC = #{lyric}, VISIBLE_FLG = #{visibleFlg}, CLASSICAL = #{classical},
WHERE ID = #{id}
